configuration.script:
	  /*
  	 * This script is returning a plain version from the annotated git tag when
	   * the at that tagged commit, or the next patch version w/ '-SNAPSHOT' added
	   * otherwise.
	   */

		def qualifiers = []

		qualifiers.add(metadata.CURRENT_VERSION_MAJOR)
		qualifiers.add(metadata.CURRENT_VERSION_MINOR)

		if (metadata.BASE_COMMIT_ON_HEAD && metadata.ANNOTATED && ! metadata.DIRTY) {
			qualifiers.add(metadata.CURRENT_VERSION_PATCH)
		} else {
			qualifiers.add(metadata.CURRENT_VERSION_PATCH + 1)
			qualifiers.add("SNAPSHOT")
		}

		/*
		 * Script output is the semi-colon ( ';' ) separated components of the desired
		 * version string where the semi-colons will be replaced by dots ( '.' ) and
		 * then dashes ( '-' ) for the SemVer version modifier(s).
		 */

		print qualifiers.join(';')
